function _fixNav() {
    const e = document.querySelector("header");
    let t = window.innerHeight;
    window.innerWidth < 1025 && window.scrollY > t ? e.classList.add("fixed-nav") : e.classList.remove("fixed-nav")
}
function lazyLoad() {
    [].map.call(lazyImages, function(e) {
        e.offsetTop < window.innerHeight + window.pageYOffset + inAdvance && !e.classList.contains("loaded") && ("img" == e.nodeName.toLowerCase() ? (e.src = e.dataset.src,
        e.onload = function() {
            e.classList.add("loaded")
        }
        ,
        console.log("img")) : e.classList.add("loaded"))
    })
}
function faqHideAll() {
    [].map.call(faqItem, function(e) {
        e.classList.remove("fc-open")
    })
}
async function webShare() {
    const e = "niggerroulette.com"
      , t = "Check out niggerroulette.com"
      , o = "https://niggerroulette.com/";
    try {
        await navigator.share({
            title: e,
            text: t,
            url: o
        })
    } catch (e) {
        console.log("Error sharing: " + e)
    }
}
window.addEventListener("scroll", _fixNav);
const toggleNav = document.querySelector(".head-toggle");
toggleNav.addEventListener("click", function() {
    document.querySelector("body").classList.toggle("menu-open")
}),
document.querySelector(".nav-bg").addEventListener("click", function() {
    document.querySelector("body").classList.toggle("menu-open")
});
const ogBtn = document.querySelector(".og-btn");
ogBtn && ogBtn.addEventListener("click", function(e) {
    if (e.preventDefault(),
    document.querySelector("body").classList.contains("rlt-vip-member")) {
        const e = document.querySelector("#only_girls");
        e.style.height = e.offsetHeight + "px",
        $("#only_girls p").fadeOut(200, function() {
            $(this).html("As a vip member you have full access to video chat with only women. Simply click the gender filter at the top of the chat app to set your partners desired gender.").fadeIn(200)
        }),
        $("#only_girls a").fadeOut(200)
    } else
        RouletteModule_Members.Upgrade()
});
let lazyImages = document.querySelectorAll(".lazy-load")
  , inAdvance = 300;
lazyLoad(),
window.addEventListener("scroll", lazyLoad),
window.addEventListener("resize", lazyLoad);
const faqItem = document.querySelectorAll(".fc-item");
[].map.call(faqItem, function(e) {
    e.addEventListener("click", function() {
        this.classList.contains("fc-open") ? faqHideAll() : (faqHideAll(),
        e.classList.add("fc-open"))
    })
}),
document.querySelector(".share-btn") && document.querySelector(".share-btn").addEventListener("click", webShare);
